import{_ as l,o as e,c as r,ak as i}from"./chunks/framework.aEAtsvX-.js";const _=JSON.parse('{"title":"领土战争","description":"","frontmatter":{},"headers":[],"relativePath":"plugins/land_war.md","filePath":"plugins/land_war.md","lastUpdated":1776427033000}'),n={name:"plugins/land_war.md"};function t(s,a,d,o,h,c){return e(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="领土战争" tabindex="-1">领土战争 <a class="header-anchor" href="#领土战争" aria-label="Permalink to “领土战争”">​</a></h1><p>查看全部战争相关指令：<code>/wars help</code>。</p><p>详细内容请看<a href="https://wiki.incredibleplugins.com/lands/players/general/wars%E3%80%82" target="_blank" rel="noreferrer">https://wiki.incredibleplugins.com/lands/players/general/wars。</a></p><p>本章基于上一章中领土部分的进阶内容。</p><h2 id="开战条件" tabindex="-1">开战条件 <a class="header-anchor" href="#开战条件" aria-label="Permalink to “开战条件”">​</a></h2><ol><li>成员要求： <ul><li>攻击方领土：必须拥有至少 3​ 位信任成员。</li><li>防御方领土：必须拥有至少 5​ 位信任成员。</li></ul></li><li>存款要求： <ul><li>攻击方领土：存款余额必须大于 50,000。</li><li>防御方领土：存款余额必须大于 10,000。</li></ul></li><li>存续时间要求： <ul><li>攻击方领土：必须成立超过 3​ 天。</li><li>防御方领土：必须成立超过 5​ 天。</li></ul></li></ol><h2 id="宣战流程" tabindex="-1">宣战流程 <a class="header-anchor" href="#宣战流程" aria-label="Permalink to “宣战流程”">​</a></h2><p>攻击方需在 <strong>每日早上9点至晚上11点​</strong> 之间，使用指令<code>/wars declare &lt;land&gt;</code>向目标领土发出战争宣言。 宣言发出时，防御方领土必须有成员在线。 防御方需在 <strong>5天内​</strong> 回应并接受宣战。若逾期未接受，则视为拒绝，防御方不会受到任何惩罚，此举是为了防止单方面宣战。</p><h2 id="战争中" tabindex="-1">战争中 <a class="header-anchor" href="#战争中" aria-label="Permalink to “战争中”">​</a></h2><p>持续时间：<strong>战争将持续 36小时（1.5天）。</strong> 系统提示：战争期间，系统会每隔 15分钟​ 向所有领土成员发送通知。</p><p>规则变更：战争期间，在敌对领土内，以下限制将被解除： 可以放置和破坏藤蔓、梯子、脚手架。 无视对方的物品拾取限制、玩家攻击限制以及领土进入限制。</p><h2 id="胜负与战果" tabindex="-1">胜负与战果 <a class="header-anchor" href="#胜负与战果" aria-label="Permalink to “胜负与战果”">​</a></h2><ul><li>攻击方投降：扣除其领土存款的 50%​ 给予防御方。</li><li>防御方投降：扣除其领土存款的 30%​ 给予攻击方。</li><li>获胜方将获得对方领土存款的 75%。</li></ul><h2 id="战后" tabindex="-1">战后 <a class="header-anchor" href="#战后" aria-label="Permalink to “战后”">​</a></h2><ul><li>投降方：获得持续4天​的“战争护盾”（在此期间无法被宣战）。</li><li>交战双方：无论胜负，战后均获得持续 7天​ 的“战争护盾”。</li></ul><h2 id="占领机制" tabindex="-1">占领机制 <a class="header-anchor" href="#占领机制" aria-label="Permalink to “占领机制”">​</a></h2><p>战争采用积分制。使用<code>/war menu</code>可以合成“占领旗帜”，用于占领敌方区块以获得分数。 占领流程：在目标区块放置旗帜后，需有己方成员在该区块停留 10分钟​ 才算占领成功。占领期间，系统会每隔 30秒​ 用烟花特效提示周围玩家。 旗帜归属：战争结束后，占领旗帜默认会归还给原领土。</p>',17)])])}const u=l(n,[["render",t]]);export{_ as __pageData,u as default};
